#include<bits/stdc++.h>
using namespace std;
struct node
{
    int val,id;
    bool operator<(const node&b)const
    {
        return val<b.val;
    }
}c[310];
int f[310][310],ans[310][310];
int main()
{
    int n,m,q;
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i].val);
        c[i].id=i;
    }
    sort(c+1,c+1+n);
    memset(f,0x3f,sizeof(f));
    memset(ans,0x3f,sizeof(ans));
    for(int i=1;i<=n;i++)
    {
        f[i][i]=0;
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        f[u][v]=f[v][u]=min(f[u][v],w);
    }
    for(int K=1;K<=n;K++)
    {
        int k=c[K].id;
        for(int I=1;I<=n;I++)
        {
            int i=c[I].id;
            for(int J=1;J<=n;J++)
            {
                int j=c[J].id;
                f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
                ans[i][j]=min(ans[i][j],f[i][j]+max({c[I].val,c[J].val,c[K].val}));
            }
        }
    }
    while(q--)
    {
        int s,t;
        scanf("%d%d",&s,&t);
        printf("%d\n",ans[s][t]);
    }
    return 0;
}
